            product = Product(name="Widget", price=9.99, quantity=10);
            print(f"{product.name}: ${product.total_value:.2f}");
            # Widget: $99.90

            product.restock(5);
            print(f"After restock: {product.quantity} units, ${product.total_value:.2f}");
            # After restock: 15 units, $149.85
        }
